/**
 * Update patient
 * PUT /api/patients/:id
 */
export const updatePatient = async (req, res) => {
  try {
    const { id } = req.params;
    const {
      firstName, lastName, dob, gender, bloodGroup,
      phone, alternatePhone, email, address, city, state,
      pincode, occupation, maritalStatus, emergencyContactName,
      emergencyContactPhone, emergencyContactRelation,
      insuranceProvider, insurancePolicyNumber, allergies,
      chronicConditions
    } = req.body;

    // Check if patient exists
    const existingPatient = await query('SELECT id FROM patients WHERE id = $1', [id]);
    
    if (existingPatient.rows.length === 0) {
      return res.status(404).json({
        success: false,
        message: 'Patient not found'
      });
    }

    // Build update fields dynamically
    const updateFields = [];
    const updateValues = [];
    let paramIndex = 1;

    if (firstName) {
      updateFields.push(`first_name = $${paramIndex}`);
      updateValues.push(firstName);
      paramIndex++;
    }

    if (lastName !== undefined) {
      updateFields.push(`last_name = $${paramIndex}`);
      updateValues.push(lastName);
      paramIndex++;
    }

    if (dob) {
      updateFields.push(`dob = $${paramIndex}`);
      updateValues.push(dob);
      paramIndex++;
    }

    if (gender) {
      updateFields.push(`gender = $${paramIndex}`);
      updateValues.push(gender);
      paramIndex++;
    }

    if (bloodGroup !== undefined) {
      updateFields.push(`blood_group = $${paramIndex}`);
      updateValues.push(bloodGroup);
      paramIndex++;
    }

    if (phone) {
      updateFields.push(`phone = $${paramIndex}`);
      updateValues.push(phone);
      paramIndex++;
    }

    if (alternatePhone !== undefined) {
      updateFields.push(`alternate_phone = $${paramIndex}`);
      updateValues.push(alternatePhone);
      paramIndex++;
    }

    if (email !== undefined) {
      updateFields.push(`email = $${paramIndex}`);
      updateValues.push(email);
      paramIndex++;
    }

    if (address !== undefined) {
      updateFields.push(`address = $${paramIndex}`);
      updateValues.push(address);
      paramIndex++;
    }

    if (city !== undefined) {
      updateFields.push(`city = $${paramIndex}`);
      updateValues.push(city);
      paramIndex++;
    }

    if (state !== undefined) {
      updateFields.push(`state = $${paramIndex}`);
      updateValues.push(state);
      paramIndex++;
    }

    if (pincode !== undefined) {
      updateFields.push(`pincode = $${paramIndex}`);
      updateValues.push(pincode);
      paramIndex++;
    }

    if (allergies !== undefined) {
      updateFields.push(`allergies = $${paramIndex}`);
      updateValues.push(JSON.stringify(allergies));
      paramIndex++;
    }

    if (chronicConditions !== undefined) {
      updateFields.push(`chronic_conditions = $${paramIndex}`);
      updateValues.push(JSON.stringify(chronicConditions));
      paramIndex++;
    }

    updateFields.push(`updated_at = CURRENT_TIMESTAMP`);
    updateValues.push(id);

    const updateQuery = `
      UPDATE patients 
      SET ${updateFields.join(', ')}
      WHERE id = $${paramIndex}
      RETURNING *
    `;

    const result = await query(updateQuery, updateValues);

    // Log audit
    await query(
      `INSERT INTO audit_logs (user_id, action, entity_type, entity_id, new_values, ip_address, user_agent)
       VALUES ($1, $2, $3, $4, $5, $6, $7)`,
      [
        req.user.id,
        'UPDATE',
        'Patient',
        id,
        JSON.stringify(req.body),
        req.ip,
        req.get('user-agent')
      ]
    );

    res.status(200).json({
      success: true,
      message: 'Patient updated successfully',
      data: {
        patient: result.rows[0]
      }
    });
  } catch (error) {
    console.error('Update patient error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to update patient'
    });
  }
};

/**
 * Get patient's visit history
 * GET /api/patients/:id/history
 */
export const getPatientHistory = async (req, res) => {
  try {
    const { id } = req.params;

    // Get encounters
    const encountersResult = await query(
      `SELECT e.*, u.name as doctor_name, u.specialization
       FROM encounters e
       JOIN users u ON e.doctor_id = u.id
       WHERE e.patient_id = $1
       ORDER BY e.encounter_date DESC
       LIMIT 50`,
      [id]
    );

    // Get lab tests
    const labTestsResult = await query(
      `SELECT lt.*, u.name as doctor_name
       FROM lab_tests lt
       JOIN users u ON lt.doctor_id = u.id
       WHERE lt.patient_id = $1
       ORDER BY lt.created_at DESC
       LIMIT 50`,
      [id]
    );

    // Get prescriptions
    const prescriptionsResult = await query(
      `SELECT p.*, e.encounter_date
       FROM prescriptions p
       JOIN encounters e ON p.encounter_id = e.id
       WHERE e.patient_id = $1
       ORDER BY e.encounter_date DESC
       LIMIT 100`,
      [id]
    );

    res.status(200).json({
      success: true,
      data: {
        encounters: encountersResult.rows,
        labTests: labTestsResult.rows,
        prescriptions: prescriptionsResult.rows
      }
    });
  } catch (error) {
    console.error('Get patient history error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to fetch patient history'
    });
  }
};

/**
 * Get patient statistics
 * GET /api/patients/stats
 */
export const getPatientStats = async (req, res) => {
  try {
    const stats = await query(`
      SELECT 
        COUNT(*) as total_patients,
        COUNT(*) FILTER (WHERE gender = 'Male') as male_count,
        COUNT(*) FILTER (WHERE gender = 'Female') as female_count,
        COUNT(*) FILTER (WHERE created_at >= CURRENT_DATE) as today_registrations,
        COUNT(*) FILTER (WHERE created_at >= CURRENT_DATE - INTERVAL '7 days') as week_registrations,
        COUNT(*) FILTER (WHERE created_at >= CURRENT_DATE - INTERVAL '30 days') as month_registrations,
        ROUND(AVG(EXTRACT(YEAR FROM AGE(dob))), 1) as avg_age
      FROM patients
    `);

    res.status(200).json({
      success: true,
      data: {
        stats: stats.rows[0]
      }
    });
  } catch (error) {
    console.error('Get patient stats error:', error);
    res.status(500).json({
      success: false,
      message: 'Failed to fetch statistics'
    });
  }
};

export default {
  createPatient,
  getAllPatients,
  getPatientById,
  getPatientByUhid,
  updatePatient,
  getPatientHistory,
  getPatientStats
};
